import { saveKnowledge, saveFile, installSkill } from './tools';
import { executeWebSearch, executeScraping } from './skill_executor';
import { detectIntent, SUB_AGENTS, CF_MODELS } from './sub_agents';
import { addMessage, getHistory } from './memory';
import * as path from 'path';
import * as fs from 'fs';

function loadEnv(): Record<string, string> {
    const vars: Record<string, string> = {};
    Object.keys(process.env).forEach(key => { vars[key] = process.env[key] || ''; });
    const envPath = path.resolve(process.cwd(), '.env');
    if (fs.existsSync(envPath)) {
        const content = fs.readFileSync(envPath, 'utf-8');
        content.split('\n').forEach((line) => {
            const trimmed = line.trim();
            if (!trimmed || trimmed.startsWith('#')) return;
            const eqIdx = trimmed.indexOf('=');
            if (eqIdx !== -1) {
                let val = trimmed.substring(eqIdx + 1).trim();
                if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                    val = val.slice(1, -1);
                }
                vars[trimmed.substring(0, eqIdx).trim()] = val;
            }
        });
    }
    return vars;
}

async function fetchWithTimeout(apiUrl: string, auth: string | Record<string, string>, payload: Record<string, unknown>, timeoutMs = 15000): Promise<{ ok: boolean; data?: any; error?: string }> {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);
    try {
        let headers: Record<string, string> = { 'Content-Type': 'application/json' };
        if (typeof auth === 'string' && auth) {
            headers['Authorization'] = `Bearer ${auth.trim()}`;
        } else if (typeof auth === 'object') {
            headers = { ...headers, ...auth };
        }

        const response = await fetch(apiUrl, {
            method: 'POST',
            headers,
            body: JSON.stringify(payload),
            signal: controller.signal
        });
        clearTimeout(timer);
        if (!response.ok) {
            const errText = await response.text().catch(() => "Unknown");
            return { ok: false, error: `HTTP ${response.status}: ${errText.substring(0, 150)}` };
        }
        const data = await response.json();
        return { ok: true, data };
    } catch (e: any) {
        clearTimeout(timer);
        return { ok: false, error: e.name === 'AbortError' ? 'TIMEOUT' : e.message };
    }
}

async function handleToolCalls(text: string): Promise<{ cleanText: string; toolResults: string[] }> {
    let cleanText = text;
    const toolResults: string[] = [];

    const memoryRegex = /\[SAVE_MEMORY:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(low|medium|high|critical)\]/gi;
    const fileRegex = /\[SAVE_FILE:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\]/gi;
    const searchRegex = /\[WEB_SEARCH:\s*(.*?)\]/gi;
    const scrapeRegex = /\[SCRAPE:\s*(.*?)\]/gi;
    const createSkillRegex = /\[CREATE_SKILL:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\]/gi;

    let match;
    while ((match = memoryRegex.exec(text)) !== null) {
        const [full, content, title, tags, importance] = match;
        await saveKnowledge({
            content, title, tags: tags.split(','),
            importance: importance as any, source: 'agent'
        }).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    while ((match = fileRegex.exec(text)) !== null) {
        const [full, content, name, fpath] = match;
        await saveFile(name, fpath, content).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    while ((match = searchRegex.exec(text)) !== null) {
        const [full, query] = match;
        const result = await executeWebSearch(query);
        toolResults.push(`### RESULTADO BÚSQUEDA (${query}):\n${result}`);
        cleanText = cleanText.replace(full, '');
    }

    while ((match = scrapeRegex.exec(text)) !== null) {
        const [full, url] = match;
        const result = await executeScraping(url);
        toolResults.push(`### CONTENIDO SCRAPING (${url}):\n${result}`);
        cleanText = cleanText.replace(full, '');
    }

    while ((match = createSkillRegex.exec(text)) !== null) {
        const [full, name, description, uri, caps] = match;
        await installSkill({
            name, description, mcpUri: uri,
            capabilities: caps.split(',').map(c => c.trim())
        }).catch(() => { });
        cleanText = cleanText.replace(full, `✅ **Skill Creada e Instalada:** ${name}`);
    }

    return { cleanText: cleanText.trim(), toolResults };
}

export async function processAiMessage(input: string | any[]) {
    const env = loadEnv();
    const chatMessages = typeof input === 'string' ? [{ role: 'user', content: input }] : input;
    const userMessage = chatMessages[chatMessages.length - 1].content;

    let history: any[] = [];
    try { history = await getHistory(8); } catch (e) { }

    const hasImage = chatMessages.some(m => m.image);
    const intent = detectIntent(userMessage, hasImage);
    const agent = SUB_AGENTS[intent] || SUB_AGENTS['chat'];

    // Modo Eficiencia: Selecciona el modelo más barato de la categoría requerida
    const tierModels = CF_MODELS[agent.tier] || CF_MODELS['ultra_cheap'];
    const selectedCfModel = tierModels[0].model; // El primero es siempre el más barato del tier

    const sysPrompt = `IDENTIDAD: Eres OpenGravity v4 - EXECUTOR. ROLE: ${agent.name}.\nREGLA DE ORO: Si el usuario pide una web o código, responde ÚNICAMENTE con el bloque de código markdown. PROHIBIDO EXPLICAR O HABLAR. Si quieres decir algo, hazlo después del código en una sola línea corta: "Interfaz renderizada en el playground".\nFORMATO: Usa bloques de código markdown con el lenguaje correcto (html, javascript, etc.). El Playground de la derecha capturará este código automáticamente.\nINSTRUCCIONES EXTRA: ${agent.instructions}`;

    const providers: any[] = [];

    // 1. Prioridad: Cloudflare AI (Routing Inteligente + Gratis/Eficiente)
    const cfAcc = env.CLOUDFLARE_ACCOUNT_ID;
    const cfEmail = env.CLOUDFLARE_EMAIL;
    const cfKey = env.CLOUDFLARE_GLOBAL_KEY;

    if (cfAcc && cfEmail && cfKey) {
        providers.push({
            id: `CF AI (${agent.tier})`,
            auth: { "X-Auth-Email": cfEmail, "X-Auth-Key": cfKey },
            url: `https://api.cloudflare.com/client/v4/accounts/${cfAcc}/ai/run/${selectedCfModel}`,
            model: selectedCfModel,
            type: "cloudflare"
        });
    }

    // 2. Fallbacks
    const cerKey = env.CEREBRAS_API_KEY;
    if (cerKey && cerKey.length > 10) {
        providers.push({ id: "Cerebras", auth: cerKey, url: "https://api.cerebras.ai/v1/chat/completions", model: "llama3.1-8b", type: "openai" });
    }

    // 3. Fallback 2: Gemini
    for (let i = 1; i <= 3; i++) {
        const k = env[`GEMINI_KEY_${i}`];
        if (k && k.length > 20) {
            providers.push({ id: `Gemini-${i}`, auth: '', url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${k}`, model: "gemini-1.5-flash", type: "gemini_native" });
        }
    }

    if (providers.length === 0) {
        return { reply: "❌ No se encontraron llaves de configuración.", engine: "OFFLINE" };
    }

    const failureLog: string[] = [];
    for (const p of providers) {
        try {
            if (p.type === 'gemini_native') {
                const contents = chatMessages.slice(-4).map((msg: any) => {
                    const parts: any[] = [{ text: msg.role === 'assistant' ? msg.content : `${sysPrompt}\n\nUSER: ${msg.content}` }];
                    if (msg.image && msg.role === 'user') {
                        const [mimePart, dataPart] = msg.image.split(';base64,');
                        parts.push({
                            inline_data: {
                                mime_type: mimePart.split(':')[1],
                                data: dataPart
                            }
                        });
                    }
                    return { role: msg.role === 'assistant' ? 'model' : 'user', parts };
                });

                const res = await fetchWithTimeout(p.url, '', { contents });
                if (res.ok) {
                    const reply = res.data?.candidates?.[0]?.content?.parts?.[0]?.text;
                    if (reply) {
                        const { cleanText } = await handleToolCalls(reply);
                        await addMessage('user', userMessage);
                        await addMessage('assistant', cleanText);
                        return { reply: cleanText, engine: p.id };
                    }
                }
                failureLog.push(`${p.id}: ${res.error || 'Empty'}`);
            } else if (p.type === 'cloudflare') {
                const payload = {
                    messages: [
                        { role: 'system', content: sysPrompt },
                        ...history.slice(-4).map(h => ({ role: h.role === 'assistant' ? 'assistant' : 'user', content: h.content })),
                        { role: 'user', content: userMessage }
                    ]
                };
                const res = await fetchWithTimeout(p.url, p.auth, payload);
                if (res.ok) {
                    const reply = res.data?.result?.response;
                    if (reply) {
                        const { cleanText } = await handleToolCalls(reply);
                        await addMessage('user', userMessage);
                        await addMessage('assistant', cleanText);
                        return { reply: cleanText, engine: `${p.id} [${p.model}]` };
                    }
                }
                failureLog.push(`${p.id}: ${res.error || 'Empty'}`);
            } else {
                const payload = {
                    model: p.model,
                    messages: [
                        { role: 'system', content: sysPrompt },
                        ...history.slice(-6).map(h => ({ role: h.role === 'assistant' ? 'assistant' : 'user', content: h.content })),
                        { role: 'user', content: userMessage }
                    ]
                };
                const res = await fetchWithTimeout(p.url, p.auth, payload);
                if (res.ok) {
                    const reply = res.data?.choices?.[0]?.message?.content;
                    if (reply) {
                        const { cleanText } = await handleToolCalls(reply);
                        await addMessage('user', userMessage);
                        await addMessage('assistant', cleanText);
                        return { reply: cleanText, engine: p.id };
                    }
                }
                failureLog.push(`${p.id}: ${res.error || 'Empty'}`);
            }
        } catch (e: any) {
            failureLog.push(`${p.id}: Error ${e.message}`);
        }
    }

    return {
        reply: `⚠️ **ERROR TÉCNICO:**\nFallo de conexión en todas las APIs.\n\n**Razones:**\n${failureLog.slice(0, 3).map(f => `> ${f}`).join('\n')}`,
        engine: "OFFLINE"
    };
}
